UPDATE MEMBER
	SET MEMBER_NAME = #{memberName}
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER
	SET MEMBER_PWD = #{memberPwd}
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER
	SET MEMBER_STATUS = 'WITHDRAW'
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER
	SET MEMBER_PROFILE_IMG = #{memberProfileImg}
WHERE MEMBER_ID = #{memberId}
